        libc::SIGALRM => SIG_ALRM.store(true, Ordering::SeqCst),
        libc::SIGHUP | libc::SIGINT | libc::SIGQUIT | libc::SIGILL |
        libc::SIGTRAP | libc::SIGABRT | libc::SIGEMT | libc::SIGFPE |
        libc::SIGBUS | libc::SIGSEGV | libc::SIGSYS | libc::SIGPIPE |
        libc::SIGTERM | libc::SIGXCPU | libc::SIGXFSZ | libc::SIGVTALRM |
        libc::SIGPROF | libc::SIGUSR1 | libc::SIGUSR2 => {
            SIG_TERM.store(signo, Ordering::SeqCst);
        }
        _ => SIG_OTHER.store(signo, Ordering::SeqCst),
    }
