use std::env;
use std::ffi::OsStr;
use std::io::{self, Write};
use std::os::unix::fs::OpenOptionsExt;
use std::os::unix::io::{AsRawFd, RawFd};
use std::os::unix::process::CommandExt;
use std::path::Path;
use std::process;

const FILENAME: &str = "nohup.out";
const EXIT_NOEXEC: i32 = 126;
const EXIT_NOTFOUND: i32 = 127;
const EXIT_MISC: i32 = 127;

fn main() {
    let args: Vec<String> = env::args().collect();

    // Parse arguments - nohup takes no options, just -- to stop processing
    let mut argv = &args[1..];
    if argv.first().map_or(false, |a| a == "--") {
        argv = &argv[1..];
    }

    if argv.is_empty() {
        usage();
    }

    // If stdout is a tty, redirect to nohup.out
    let out_path = if isatty(io::stdout().as_raw_fd()) {
        dofile().unwrap_or_else(|_| {
            eprintln!("can't open a nohup.out file");
            process::exit(EXIT_MISC);
        })
    } else {
        None
    };

    // If stderr is a tty, dup stdout to stderr
    if isatty(io::stderr().as_raw_fd()) {
        // Need to dup stdout fd to stderr fd
        // This is tricky in Rust without libc...
    }

    // Ignore SIGHUP
    unsafe {
        libc::signal(libc::SIGHUP, libc::SIG_IGN as _);
    }

    // Execute the command
    let cmd = &argv[0];
    let args = &argv[1..];

    let result = process::Command::new(cmd)
        .args(args)
        .exec();

    // If we get here, exec failed
    match result {
        Err(e) if e.kind() == io::ErrorKind::NotFound => {
            eprintln!("nohup: {}: {}", cmd, e);
            process::exit(EXIT_NOTFOUND);
        }
        Err(e) => {
            eprintln!("nohup: {}: {}", cmd, e);
            process::exit(EXIT_NOEXEC);
        }
        Ok(_) => unreachable!(),
    }
