// Constants
const PI: f64 = 3.14159265358979323846;
const EPOCH: i32 = 85;
const EPSILONg: f64 = 279.611371;
const RHOg: f64 = 282.680403;
const ECCEN: f64 = 0.01671542;
const lzero: f64 = 18.251907;
const Pzero: f64 = 192.917585;
const Nzero: f64 = 55.204723;

fn isleap(y: i32) -> bool {
    (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0)
}

fn adj360(deg: &mut f64) {
    loop {
        if *deg < 0.0 {
            *deg += 360.0;
        } else if *deg > 360.0 {
            *deg -= 360.0;
        } else {
            break;
        }
    }
}

fn dtor(deg: f64) -> f64 {
    deg * PI / 180.0
}

fn potm(days: f64) -> f64 {
    let mut N = 360.0 * days / 365.2422;
    adj360(&mut N);
    let mut Msol = N + EPSILONg - RHOg;
    adj360(&mut Msol);
    let Ec = 360.0 / PI * ECCEN * Msol.sin();
    let LambdaSol = N + Ec + EPSILONg;
    let LambdaSol = adj360_val(LambdaSol);
    let mut l = 13.1763966 * days + lzero;
    adj360(&mut l);
    let mut Mm = l - (0.1114041 * days) - Pzero;
    adj360(&mut Mm);
    let mut Nm = Nzero - (0.0529539 * days);
    adj360(&mut Nm);
    let Ev = 1.2739 * (2.0 * (l - LambdaSol) - Mm).sin();
    let Ac = 0.1858 * Msol.sin();
    let A3 = 0.37 * Msol.sin();
    let Mmprime = Mm + Ev - Ac - A3;
    let Ec = 6.2886 * Mmprime.sin();
    let A4 = 0.214 * (2.0 * Mmprime).sin();
    let lprime = l + Ev + Ec - Ac + A4;
    let V = 0.6583 * (2.0 * (lprime - LambdaSol)).sin();
    let ldprime = lprime + V;
    let D = ldprime - LambdaSol;
    50.0 * (1.0 - D.cos())
}
